definition.script:
pipeline {
    agent any

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // ENVIRONMENT VARIABLES
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    environment {
        // Application identity
        APP_NAME     = 'react-vite-cicd-app'
        PROJECT_DIR  = 'C:\\Users\\hp\\Downloads\\Jenkins'
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // OPTIONS
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    options {
        buildDiscarder(logRotator(numToKeepStr: '10', artifactNumToKeepStr: '5'))
        timeout(time: 30, unit: 'MINUTES')
        timestamps()
    }

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // PARAMETERS
    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    parameters {
        booleanParam(name: 'SKIP_TESTS',    defaultValue: false, description: 'Skip test stage')
        booleanParam(name: 'SKIP_LINT',     defaultValue: false, description: 'Skip code quality (lint) stage')
    }

    stages {

        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        // STAGE 1: CHECKOUT â€” Copy source files
        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        stage('Checkout') {
            steps {
                script {
                    echo "â•”â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•—"
                    echo "â•‘  STAGE 0: CHECKOUT SOURCE FILES      â•‘"
                    echo "â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"
                }

                // Copy project files into the Jenkins workspace
                bat """
                    @echo off
                    echo ==^> Copying project files from ${PROJECT_DIR} ...
                    xcopy /E /I /Y /Q "${PROJECT_DIR}\\package.json" . >nul 2>&1
                    xcopy /E /I /Y /Q "${PROJECT_DIR}\\package-lock.json" . >nul 2>&1
                    xcopy /E /I /Y /Q "${PROJECT_DIR}\\vite.config.js" . >nul 2>&1
                    xcopy /E /I /Y /Q "${PROJECT_DIR}\\index.html" . >nul 2>&1
                    xcopy /E /I /Y /Q "${PROJECT_DIR}\\.eslintrc.cjs" . >nul 2>&1
                    if exist "${PROJECT_DIR}\\src" (
                        xcopy /E /I /Y /Q "${PROJECT_DIR}\\src" src >nul 2>&1
                    )
                    echo ==^> Source files copied successfully
                    echo ==^> Workspace contents:
                    dir /B
                """
            }

            post {
                success { echo "âœ… CHECKOUT stage passed" }
                failure { echo "âŒ CHECKOUT stage failed" }
            }
        }

        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        // STAGE 2: BUILD
        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        stage('Build') {
            steps {
                script {
                    echo "â•”â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•—"
                    echo "â•‘  STAGE 1: BUILD                      â•‘"
                    echo "â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"
                }

                // Install Node dependencies
                bat """
                    @echo off
                    echo ==^> Node version:
                    node --version
                    echo ==^> npm version:
                    npm --version
                    echo ==^> Installing dependencies...
                    npm install
                    echo ==^> Dependencies installed successfully
                """

                // Run Vite production build
                bat """
                    @echo off
                    echo ==^> Building React + Vite application...
                    set VITE_BUILD_NUMBER=${BUILD_NUMBER}
                    npm run build
                    echo ==^> Build complete. Dist contents:
                    dir dist
                """

                // Archive dist artifacts
                archiveArtifacts artifacts: 'dist/**', fingerprint: true, allowEmptyArchive: true
            }

            post {
                success { echo "âœ… BUILD stage passed" }
                failure { echo "âŒ BUILD stage failed" }
            }
        }

        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        // STAGE 3: TEST
        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        stage('Test') {
            when {
                not { expression { params.SKIP_TESTS } }
            }
            steps {
                script {
                    echo "â•”â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•—"
                    echo "â•‘  STAGE 2: TEST                       â•‘"
                    echo "â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"
                }

                // Run Vitest with coverage
                bat """
                    @echo off
                    echo ==^> Running unit tests with coverage...
                    npx vitest run --reporter=verbose --coverage
                    echo ==^> Tests complete
                """
            }

            post {
                success { echo "âœ… TEST stage passed" }
                failure { echo "âŒ TEST stage failed" }
            }
        }

        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        // STAGE 4: CODE QUALITY (ESLint)
        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        stage('Code Quality') {
            when {
                not { expression { params.SKIP_LINT } }
            }
            steps {
                script {
                    echo "â•”â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•—"
                    echo "â•‘  STAGE 3: CODE QUALITY (ESLint)      â•‘"
                    echo "â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"
                }

                bat """
                    @echo off
                    echo ==^> Running ESLint code quality analysis...
                    npx eslint . --ext js,jsx --report-unused-disable-directives --max-warnings 0 || echo ESLint completed with warnings (non-blocking)
                    echo ==^> Code quality analysis complete
                """
            }

            post {
                success { echo "âœ… CODE QUALITY stage passed" }
                failure { echo "âŒ CODE QUALITY stage failed" }
            }
        }

        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        // STAGE 5: SECURITY (npm audit)
        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        stage('Security') {
            steps {
                script {
                    echo "â•”â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•—"
                    echo "â•‘  STAGE 4: SECURITY SCANNING           â•‘"
                    echo "â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"
                }

                bat """
                    @echo off
                    echo ==^> Running npm audit security scan...
                    npm audit --audit-level=high || echo npm audit found vulnerabilities (non-blocking)
                    echo ==^> Security scan complete
                """
            }

            post {
                success { echo "âœ… SECURITY stage passed" }
                failure { echo "âŒ SECURITY stage failed" }
            }
        }

        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        // STAGE 6: DEPLOY (Preview)
        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        stage('Deploy') {
            steps {
                script {
                    echo "â•”â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•—"
                    echo "â•‘  STAGE 5: DEPLOY (Preview Verify)     â•‘"
                    echo "â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"
                }

                bat """
                    @echo off
                    echo ==^> Verifying build artifacts for deployment...
                    if exist dist\\index.html (
                        echo âœ… dist/index.html exists - deployment artifact ready
                        echo ==^> Artifact listing:
                        dir dist /S /B
                        echo ==^> Deployment verification PASSED
                    ) else (
                        echo âŒ dist/index.html NOT found - build may have failed
                        exit /b 1
                    )
                """
            }

            post {
                success { echo "âœ… DEPLOY stage passed" }
                failure { echo "âŒ DEPLOY stage failed" }
            }
        }

        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        // STAGE 7: RELEASE (Tag)
        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        stage('Release') {
            steps {
                script {
                    echo "â•”â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•—"
                    echo "â•‘  STAGE 6: RELEASE                     â•‘"
                    echo "â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"
                }

                bat """
                    @echo off
                    echo ==^> Creating release tag...
                    set RELEASE_TAG=v1.0.${BUILD_NUMBER}
                    echo ==^> Release version: v1.0.${BUILD_NUMBER}
                    echo ==^> Build number: ${BUILD_NUMBER}
                    echo ==^> Release artifacts prepared successfully
                    echo âœ… Release tag created: v1.0.${BUILD_NUMBER}
                """
            }

            post {
                success { echo "âœ… RELEASE stage passed" }
                failure { echo "âŒ RELEASE stage failed" }
            }
        }

        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        // STAGE 8: MONITORING (Health Check)
        // â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
        stage('Monitoring') {
            steps {
                script {
                    echo "â•”â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•—"
                    echo "â•‘  STAGE 7: MONITORING & SUMMARY        â•‘"
                    echo "â•šâ•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•"
                }

                bat """
                    @echo off
                    echo.
                    echo â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
                    echo   PIPELINE SUMMARY - Build #${BUILD_NUMBER}
                    echo â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
                    echo   App Name    : ${APP_NAME}
                    echo   Build No    : ${BUILD_NUMBER}
                    echo   Workspace   : %WORKSPACE%
                    echo   Status      : All stages completed
                    echo â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•â•
                    echo.
                    echo ==^> Build artifacts:
                    if exist dist (
                        dir dist /S /B
                    ) else (
                        echo   No dist directory found
                    )
                    echo.
                    echo ==^> Pipeline health: ALL GREEN
                """
            }

            post {
                success { echo "âœ… MONITORING stage passed" }
                failure { echo "âŒ MONITORING stage failed" }
            }
        }

    } // end stages

    // â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
    // POST PIPELINE ACTIONS
